import React, { useState, useEffect } from 'react';
import {
  CButton,
  CModal,
  CModalHeader,
  CModalTitle,
  CModalBody,
  CModalFooter,
  CForm,
  CCol,
  CFormLabel,
  CFormInput,
  CFormSelect,
  CFormTextarea,
} from '@coreui/react';
import PropTypes from 'prop-types';
import { settingsAppointments } from 'src/services/standardUsers';

const AppointmentsView = ({ refresh, selectedAppointments }) => {
  const [visible, setVisible] = useState(false);
  const [appointment, setAppointment] = useState({});
  const [statusDo, setstatusDo] = useState(selectedAppointments?.event?.extendedProps?.status)
  useEffect(() => {
    if (selectedAppointments?.event) {
      const event = selectedAppointments.event;
      setAppointment({
        client_code: event.extendedProps.client_code || '',
        client_name: event.title || '',
        client_contact: event.extendedProps.client_contact || '',
        date: event.start ? new Date(event.start).toISOString().split('T')[0] : '',
        time: event.start ? new Date(event.start).toLocaleTimeString('fr-FR', { hour: '2-digit', minute: '2-digit' }) : '',
        duration: event.extendedProps.duration, // adjust if needed
        hardware: event.extendedProps.hardware || '',
        software: event.extendedProps.software || '',
        meeting_reason: event.extendedProps.meeting_reason || '',
        description: event.extendedProps.description || '',
        status: event.extendedProps.status || '',
      });
    }
  }, [selectedAppointments]);

  const ChangeStaus = async (e) => {
    setstatusDo(e)
    const response = await settingsAppointments.updateAppointments(
      selectedAppointments?.event?.id,
      { status: e })
    if (response) {
      refresh();
      setVisible(false);
    }
  }

  return (
    <>
      <div onClick={() => setVisible(true)} style={{ cursor: 'pointer' }}>
        <b>{selectedAppointments.id}</b> — <span>{selectedAppointments.event.title}</span>
        <br />
        <small>{selectedAppointments.event.extendedProps.meeting_reason}</small>
      </div>

      <CModal alignment="center" visible={visible} onClose={() => setVisible(false)} >
        <CModalHeader onClose={() => setVisible(false)}>
          <CModalTitle>Détails du Rendez-vous</CModalTitle>
        </CModalHeader>
        <CModalBody>
          <CForm className="row g-3">
            <CCol md={3}>
              <CFormLabel>Code client</CFormLabel>
            </CCol>
            <CCol md={9}>
              <CFormInput value={appointment.client_code} disabled />
            </CCol>

            <CCol md={3}>
              <CFormLabel>Nom du client</CFormLabel>
            </CCol>
            <CCol md={9}>
              <CFormInput value={appointment.client_name} disabled />
            </CCol>

            <CCol md={3}>
              <CFormLabel>Contact client</CFormLabel>
            </CCol>
            <CCol md={9}>
              <CFormInput value={appointment.client_contact} disabled />
            </CCol>

            <CCol md={3}>
              <CFormLabel>Date</CFormLabel>
            </CCol>
            <CCol md={9}>
              <CFormInput type="date" value={appointment.date} disabled />
            </CCol>

            <CCol md={3}>
              <CFormLabel>Heure</CFormLabel>
            </CCol>
            <CCol md={9}>
              <CFormInput type="time" value={appointment.time} disabled />
            </CCol>

            <CCol md={3}>
              <CFormLabel>Durée</CFormLabel>
            </CCol>
            <CCol md={9}>
              <CFormInput value={appointment.duration} disabled />
            </CCol>

            <CCol md={3}>
              <CFormLabel>Matériel</CFormLabel>
            </CCol>
            <CCol md={9}>
              <CFormSelect value={appointment.hardware} disabled>
                <option>{appointment.hardware}</option>
              </CFormSelect>
            </CCol>

            <CCol md={3}>
              <CFormLabel>Logiciel</CFormLabel>
            </CCol>
            <CCol md={9}>
              <CFormSelect value={appointment.software} disabled>
                <option>{appointment.software}</option>
              </CFormSelect>
            </CCol>

            <CCol md={3}>
              <CFormLabel>Raison</CFormLabel>
            </CCol>
            <CCol md={9}>
              <CFormSelect value={appointment.meeting_reason} disabled>
                <option>{appointment.meeting_reason}</option>
              </CFormSelect>
            </CCol>

            <CCol md={3}>
              <CFormLabel>Description</CFormLabel>
            </CCol>
            <CCol md={9}>
              <CFormTextarea rows={4} value={appointment.description} disabled />
            </CCol>

            <CCol md={3}>
              <CFormLabel>Statut</CFormLabel>
            </CCol>
            <CCol md={9}>
              <CFormInput value={appointment.status} disabled />
            </CCol>
            <CCol md={3}>
              <CFormLabel>Changer</CFormLabel>
            </CCol>
            <CCol md={9}>
              <CFormSelect
                value={statusDo}
                onChange={(e) => ChangeStaus(e.target.value)}
              >
                <option value="">-- Sélectionner un statut --</option>
                <option value="En attente">En attente</option>
                <option value="waiting">En cours</option>
                <option value="waiting">Annulé</option>
                <option value="Terminé">Terminé</option>
              </CFormSelect>
            </CCol>
          </CForm>

        </CModalBody>
        <CModalFooter>
          <CButton color="secondary" onClick={() => setVisible(false)}>
            Fermer
          </CButton>
        </CModalFooter>
      </CModal>
    </>
  );
};

AppointmentsView.propTypes = {
  refresh: PropTypes.func.isRequired,
  selectedAppointments: PropTypes.object,
};

export default AppointmentsView;
